use note_state_lab::{published_note, NoteState};

#[test]
fn published_state_carries_a_date() {
    let note = published_note();
    match note.state {
        NoteState::Published { published_at } => {
            assert_eq!(published_at, "2026-05-18");
        }
        _ => panic!("expected a published note"),
    }
}
